#include <iostream>
#include <iomanip>
#include <cmath>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    // 1D
    int x1, x2;
    cin >> x1 >> x2;
    double d1 = abs(x1 - x2);

    // 2D
    int y1_1, y1_2, y2_1, y2_2;
    cin >> y1_1 >> y1_2 >> y2_1 >> y2_2;
    double d2 = sqrt(1.0 * (y1_1 - y2_1) * (y1_1 - y2_1) + 1.0 * (y1_2 - y2_2) * (y1_2 - y2_2));

    // 3D
    int z1_1, z1_2, z1_3, z2_1, z2_2, z2_3;
    cin >> z1_1 >> z1_2 >> z1_3 >> z2_1 >> z2_2 >> z2_3;
    double d3 = sqrt(1.0 * (z1_1 - z2_1) * (z1_1 - z2_1) + 
                     1.0 * (z1_2 - z2_2) * (z1_2 - z2_2) + 
                     1.0 * (z1_3 - z2_3) * (z1_3 - z2_3));

    cout << fixed << setprecision(3);
    cout << d1 << "\n";
    cout << d2 << "\n";
    cout << d3 << "\n";

    return 0;
}
